const express = require('express');
const app = express();
const redis = require('redis');
const client = redis.createClient({
  host: 'localhost',
  port: 6379,
});
const twilio = require('twilio');

// Twilio configuration
const accountSid = 'your_account_sid';
const authToken = 'your_auth_token';
const clientTwilio = new twilio(accountSid, authToken);

// Redis expiration time (10 minutes)
const EXPIRATION_TIME = 600;

// Function to generate a random code
function generateCode() {
  return Math.floor(Math.random() * 900000) + 100000;
}

// Function to send SMS via Twilio
async function sendSMS(phoneNumber, code) {
  const message = await clientTwilio.messages.create({
    from: 'your_twilio_phone_number',
    to: phoneNumber,
    body: `Your MFA code is ${code}`,
  });
  return message.sid;
}

// Function to store code in Redis with expiration
async function storeCode(phoneNumber, code) {
  const key = `mfa-code:${phoneNumber}`;
  await client.set(key, code, 'EX', EXPIRATION_TIME);
}

// Function to check if user has exceeded the number of attempts
async function checkAttempts(phoneNumber) {
  const key = `attempts:${phoneNumber}`;
  return await client.get(key);
}

// Middleware to handle MFA authentication
const mfaMiddleware = async (req, res, next) => {
  const phoneNumber = req.body.phoneNumber;
  const code = req.body.code;

  // Check if user has exceeded the number of attempts
  const attempts = await checkAttempts(phoneNumber);
  if (attempts >= 10) {
    return res.status(429).send({ error: 'Too many attempts' });
  }

  // Generate a new MFA code and store it in Redis
  const newCode = generateCode();
  await storeCode(phoneNumber, newCode);

  // Send the new MFA code via SMS
  sendSMS(phoneNumber, newCode)
    .then((messageSid) => {
      res.send({ message: 'MFA code sent successfully' });
    })
    .catch((err) => {
      console.error(err);
      res.status(500).send({ error: 'Failed to send MFA code' });
    });

  next();
};

// Route to accept the MFA code
app.post('/mfa', mfaMiddleware, (req, res) => {
  const phoneNumber = req.body.phoneNumber;
  const code = req.body.code;

  // Check if the provided code matches the stored one
  const key = `mfa-code:${phoneNumber}`;
  client.get(key, (err, storedCode) => {
    if (err) {
      console.error(err);
      res.status(500).send({ error: 'Failed to retrieve MFA code' });
    } else if (storedCode === code) {
      // Grant access if the codes match
      res.send({ message: 'MFA authentication successful' });
      client.del(key); // Delete the stored code
    } else {
      // Increment attempts and return an error
      const attemptsKey = `attempts:${phoneNumber}`;
      client.incr(attemptsKey, (err) => {
        if (err) {
          console.error(err);
          res.status(500).send({ error: 'Failed to increment attempts' });
        } else {
          res.status(401).send({ error: 'Invalid MFA code' });
        }
      });
    }
  });
});

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});